            case 'template2':
                return <QuotationTemplate2 ref={ref} data={data} ignoreHidden={ignoreHidden} />;
            default:
                return <QuotationTemplate2 ref={ref} data={data} ignoreHidden={ignoreHidden} />;
        }
    };

    return (
        <InvoiceWrapper template={template}>
            {renderTemplate()}
        </InvoiceWrapper>
    );
});

