const EmptyCategory = { id: '', name: '' };
const AddCategoryModal = ({ isOpen, categoryToUpdate,  }) => {
  const [category, setCategory] = useState(categoryToUpdate || EmptyCategory);
  const dispatch = useDispatch();

  const user = useSelector(selectUser);

  useEffect(() => {
    if (categoryToUpdate) {setCategory(categoryToUpdate);}
  }, [categoryToUpdate]);

  const onClose = () => {
    dispatch(toggleAddCategory({ isOpen: false, data: null }));
    setCategory(EmptyCategory);
  };

  const handleSubmit = (event) => {
    event.preventDefault();
    if (category.name === '') {
      dispatch(addNotification({
        message: 'El nombre de la categoría no puede estar vacío',
        type: 'error',
      }))
      return
    }

    if (categoryToUpdate) {
      fbUpdateCategory(category, user)
        .then(() => { onClose(); })
        .then(() => {
          dispatch(addNotification({
            message: 'Categoría actualizada con éxito',
            type: 'success',
          }))
          return
        })
    } else {
      fbAddCategory(category, user)
        .then(() => { onClose(); })
        .then(() => {
          dispatch(addNotification({
            message: 'Categoría creada con éxito',
            type: 'success',
          }))
        });
    }
  };

  return (
    <ModalOverlay
      variants={OverlayVariants}
      initial="closed"
      animate={isOpen ? "open" : "closed"}
      exit="closed"
      transition={{ duration: 0.3 }}
      isOpen={isOpen}
    >
      <ModalContainer
        variants={ContainerVariants}
        initial="closed"
        animate={isOpen ? "open" : "closed"}
        exit="closed"
      >
        <h2>{categoryToUpdate ? 'Actualizar Categoría' : 'Crear Categoría'}</h2>
        <Form onSubmit={handleSubmit}>
          <InputV4
            name='name'
            placeholder='Nombre de la Categoría'
            onChange={(e) => setCategory({ ...category, name: e.target.value })}
            size='medium'
            value={category.name}
          />
          <ButtonGroup>
            <Button type="button" onClick={onClose}>
              Cancelar
            </Button>
            {categoryToUpdate ? (
              <Button type="submit">{'Actualizar'}</Button>
            ) : (
              <Button type="submit">{'Crear'}</Button>
            )}
          </ButtonGroup>
        </Form>
      </ModalContainer>
    </ModalOverlay>
  );
};

