import { Checkbox, Divider, Typography } from 'antd';
import React, { useState, useEffect } from 'react';
import styled from 'styled-components';

const { Title, Text } = Typography;

const FieldSelector = ({ essentialFields, optionalGroups, onFieldsChange, language = 'es' }) => {
  // Aplanar todos los campos opcionales en una sola lista
  const flattenedOptionalFields = Object.values(optionalGroups).flat();

  const [selectedFields, setSelectedFields] = useState([]);
  const [indeterminate, setIndeterminate] = useState(false);
  const [checkAll, setCheckAll] = useState(false);

  useEffect(() => {
    // Notificar al componente padre sobre los cambios
    onFieldsChange(selectedFields);
  }, [selectedFields, onFieldsChange]);

  const handleChange = (checkedValues) => {
    setSelectedFields(checkedValues);
    setIndeterminate(!!checkedValues.length && checkedValues.length < flattenedOptionalFields.length);
    setCheckAll(checkedValues.length === flattenedOptionalFields.length);
  };

  const handleCheckAllChange = (e) => {
    setSelectedFields(e.target.checked ? [...flattenedOptionalFields] : []);
    setIndeterminate(false);
    setCheckAll(e.target.checked);
  };

  return (
    <Container>
      <div>
        <Title level={5}>Campos esenciales</Title>
        <Text type="secondary">Los siguientes campos siempre se incluirán en la plantilla:</Text>
        <EssentialList>
          {essentialFields.map(field => (
            <EssentialField key={field}>{field}</EssentialField>
          ))}
        </EssentialList>
      </div>

      <Divider />

      <div>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <Title level={5}>Campos opcionales</Title>
          <Checkbox 
            indeterminate={indeterminate} 
            onChange={handleCheckAllChange} 
            checked={checkAll}
          >
            Seleccionar todos
          </Checkbox>
        </div>

        <Text type="secondary">Selecciona los campos adicionales que deseas incluir:</Text>

        <CheckboxGroup 
          options={flattenedOptionalFields.map(field => ({ label: field, value: field }))} 
          value={selectedFields} 
          onChange={handleChange}
        />
      </div>
    </Container>
  );
};

export default FieldSelector;

const Container = styled.div`
  margin: 20px 0;
`;

const EssentialList = styled.div`
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  margin: 10px 0;
`;

const EssentialField = styled.div`
  background-color: #f0f0f0;
  border-radius: 4px;
  padding: 4px 8px;
  font-size: 0.9em;
`;

const CheckboxGroup = styled(Checkbox.Group)`
  display: flex;
  flex-direction: column;
  margin-top: 10px;
  max-height: 300px;
  overflow-y: auto;
  padding: 10px 0;

  .ant-checkbox-wrapper {
    margin: 5px 0;
  }
`;

import * as antd from 'antd';
import React, { useEffect, useState } from 'react';

const { Button, Upload, Modal, message, Tabs } = antd;
import { FileAddOutlined, UploadOutlined } from '@ant-design/icons';
import styled from 'styled-components';

import { getAvailableHeaders } from '../../../../utils/import/product/filterEssentialHeaders';
import { productHeaderMappings } from '../../../../utils/import/product/headerMappings';

import FieldSelector from './FieldSelector';

export default function ImportModal({ open, onClose, onImport, onCreateTemplate }) {
  const [fileList, setFileList] = useState([]);
  const [isImporting, setIsImporting] = useState(false);
  const [activeTab, setActiveTab] = useState("import");
  const [selectedOptionalFields, setSelectedOptionalFields] = useState([]);
  const [language] = useState('es'); // Por defecto español, podría ser configurable en el futuro

  // Obtener los campos disponibles
  const { essential, optionalGroups } = getAvailableHeaders(productHeaderMappings, language);

  const handleImportClick = async () => {
    if (fileList.length > 0 && fileList[0].originFileObj) {
      setIsImporting(true);
      try {
        await onImport(fileList[0].originFileObj);
        setFileList([]);
        onClose();
        message.success('Datos importados exitosamente');
      } catch (error) {
        console.error('Error al importar datos:', error);
        message.error('Hubo un problema al importar los datos. Por favor, verifica el archivo e intenta de nuevo.');
      } finally {
        setIsImporting(false);
      }
    } else {
      message.error('Por favor, selecciona un archivo válido para importar.');
    }
  };

  const handleCreateTemplateClick = async () => {
    try {
      await onCreateTemplate(language, selectedOptionalFields);
      message.success('Plantilla creada exitosamente.');
    } catch (error) {
      console.error('Error al crear la plantilla:', error);
      message.error('Hubo un problema al crear la plantilla.');
    }
  };

  const handleFieldsChange = (fields) => {
    setSelectedOptionalFields(fields);
  };

  const handleFileChange = ({ file, fileList }) => {
    setFileList(fileList);

    if (file.status === 'done') {
      message.success(`${file.name} se ha seleccionado correctamente.`);
    } else if (file.status === 'error') {
      message.error(`${file.name} no se pudo seleccionar.`);
    }
  };

  useEffect(() => {
    if (!open) {
      setFileList([]);
    }
  }, [open]);

  const isValidFileType = (file) => {
    const validTypes = [
      'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      'text/csv',
      'application/csv',
      'text/x-csv',
      'application/x-csv',
      'text/comma-separated-values',
      'text/x-comma-separated-values'
    ];

    if (validTypes.includes(file.type)) {
      return true;
    }

    const validExtensions = ['xlsx', 'csv'];
    const extension = file.name.split('.').pop().toLowerCase();

    // Verificar específicamente archivos .xls y mostrar error informativo
    if (extension === 'xls') {
      message.error({
        content: (
          <div>
            <div style={{ fontWeight: 'bold', marginBottom: '8px' }}>
              ❌ Archivo .xls no compatible
            </div>
            <div style={{ marginBottom: '4px' }}>
              💡 <strong>Soluciones:</strong>
            </div>
            <div style={{ fontSize: '12px', lineHeight: '1.4' }}>
              • Guarda el archivo como .xlsx desde Excel<br/>
              • Exporta como CSV desde Excel<br/>
              • Usa LibreOffice para convertir a .xlsx
            </div>
          </div>
        ),
        duration: 8
      });
      return false;
    }

    return validExtensions.includes(extension);
  };

  const uploadProps = {
    onRemove: () => {
      setFileList([]);
    },
    beforeUpload: (file) => {
      if (!isValidFileType(file)) {
        message.error('Solo se permiten archivos Excel (.xlsx, .xls) o CSV.');
        return Upload.LIST_IGNORE;
      }
      const isLt10M = file.size / 1024 / 1024 < 10;
      if (!isLt10M) {
        message.error('El archivo debe ser menor a 10MB.');
        return Upload.LIST_IGNORE;
      }
      return false; // Prevent auto upload
    },
    fileList,
  };

  const items = [
    {
      key: 'import',
      label: 'Importar Datos',
      children: (
        <Section>
          <p>Selecciona un archivo Excel (.xlsx) o CSV para importar datos al sistema.</p>
          <p>⚠️ <strong>Nota:</strong> Los archivos .xls antiguos no son compatibles. Por favor, guárdalos como .xlsx o CSV desde Excel.</p>
          <p>Asegúrate de que los datos estén organizados de acuerdo a la plantilla de importación.</p>

          <Upload
            {...uploadProps}
            onChange={handleFileChange}
            maxCount={1}
          >
            <Button icon={<UploadOutlined />}>Elegir archivo</Button>
          </Upload>
        </Section>
      ),
    },
    {
      key: 'template',
      label: 'Crear Plantilla',
      children: (
        <Section>
          <p>Crea una plantilla personalizada seleccionando los campos que necesitas.</p>
          <p>Los campos esenciales siempre se incluirán en la plantilla.</p>

          <FieldSelector 
            essentialFields={essential}
            optionalGroups={optionalGroups}
            onFieldsChange={handleFieldsChange}
            language={language}
          />

          <Button
            type="primary"
            onClick={handleCreateTemplateClick}
            icon={<FileAddOutlined />}
          >
            Crear Plantilla
          </Button>
        </Section>
      ),
    },
  ];

  return (
    <StyledModal
      title="Importar Datos"
      open={open}
      onCancel={onClose}
      footer={
        activeTab === 'import' 
          ? [
              <Button key="cancel" onClick={onClose}>
                Cancelar
              </Button>,
              <Button
                key="import"
                type="primary"
                onClick={handleImportClick}
                disabled={fileList.length === 0 || isImporting}
                loading={isImporting}
              >
                <UploadOutlined />
                {isImporting ? 'Importando...' : 'Importar'}
              </Button>,
            ]
          : [
              <Button key="cancel" onClick={onClose}>
                Cerrar
              </Button>,
            ]
      }
    >
      <Body>
        <Tabs 
          activeKey={activeTab} 
          onChange={setActiveTab}
          items={items}
        />
      </Body>
    </StyledModal>
  );
}

const StyledModal = styled(Modal)`
  .ant-modal-footer {
    display: flex;
    justify-content: space-between;
  }
`;

const Body = styled.div`
  min-height: 15em;
`;

const Section = styled.div`
  margin-bottom: 2em;
  p {
    margin-bottom: 1em;
  }
`;

