import * as antd from 'antd';
import React, { useEffect, useMemo, useState, useRef } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { ExclamationCircleOutlined } from '@ant-design/icons';

const { Form, Button, Modal, Alert, message } = antd;
import { selectUser } from '../../../../features/auth/userSlice';
import { changeClientInvoiceForm, changeValueInvoiceForm, closeInvoiceForm, selectInvoice } from '../../../../features/invoice/invoiceFormSlice';
import { markAuthorizationUsed } from '../../../../firebase/authorizations/invoiceEditAuthorizations';
import { fbUpdateInvoice } from '../../../../firebase/invoices/fbUpdateInvoice';
import { useFormatPrice } from '../../../../hooks/useFormatPrice';
import { convertInvoiceDateToMillis } from '../../../../utils/invoice';

import { InvoiceInfo } from './components/InvoiceInfo/InfoiceInfo';
import { Products } from './components/Products/Products';

export const InvoiceForm = () => {

  const [form] = Form.useForm();
  const [loading, setLoading] = useState(false);
  const ignoreDiscountChangeRef = useRef(false);
  const { invoice, modal, authorizationRequest } = useSelector(selectInvoice)
  const dispatch = useDispatch();
  const user = useSelector(selectUser);

  const isEditLocked = useMemo(() => {
    if (!invoice?.date) return true;
    const timestamp = convertInvoiceDateToMillis(invoice.date);
    if (!Number.isFinite(timestamp)) return true;

    const elapsedMs = Date.now() - timestamp;
    const limitMs = 48 * 60 * 60 * 1000;

    return elapsedMs >= limitMs;
  }, [invoice?.date]);

  const handleOk = async () => {
    if (isEditLocked) {
      message.warning('Esta factura superó el límite de 48 horas y no puede modificarse.');
      return;
    }

    try {
      setLoading(true);
      await form.validateFields();
      await fbUpdateInvoice(user, invoice);

      if (authorizationRequest?.id) {
        try {
          await markAuthorizationUsed(user, authorizationRequest.id, user);
        } catch (markError) {
          console.warn('No se pudo marcar la autorización como usada', markError);
          antd.message.warning('Factura actualizada, pero la autorización no pudo marcarse como usada.');
        }
      }

      dispatch(closeInvoiceForm());
      antd.message.success('Factura actualizada correctamente');
    } catch (info) {
      antd.message.error('Error al actualizar factura');
      console.error('Validate Failed or Update Failed:', info);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (!modal?.isOpen) return;
    form.setFieldsValue(invoice);
  }, [form, invoice, modal?.isOpen]);

  const sections = useMemo(() => ([
    {
      key: "1",
      label: "General",
      children: <InvoiceInfo invoice={invoice} isEditLocked={isEditLocked} />
    },
    {
      key: "2",
      label: "Productos",
      children: <Products invoice={invoice} isEditLocked={isEditLocked} />
    }
  ]), [invoice, isEditLocked])

  const handleCancel = () => {
    if (loading) return;
    dispatch(closeInvoiceForm())
  };

  const handleChange = (value) => {
    if (isEditLocked) return;

    const key = Object.keys(value)[0]
    if (!key) return;

    if (key === 'discount' && ignoreDiscountChangeRef.current) {
      ignoreDiscountChangeRef.current = false;
      return;
    }

    if (key === 'client') {
      dispatch(changeClientInvoiceForm(value))
      return    
    }
    if (key === 'discount') {
      const previousValue = Number(invoice?.discount?.value) || 0;
      const rawValue = Number(value?.discount?.value);
      const numericValue = Number.isFinite(rawValue) ? rawValue : 0;

      let normalizedValue = Math.max(0, numericValue);

      if (normalizedValue > 99) {
        message.warning('El descuento no puede superar el 99%.');
        normalizedValue = 99;
      }

      if (normalizedValue !== numericValue) {
        ignoreDiscountChangeRef.current = true;
        form.setFieldsValue({ discount: { value: normalizedValue } });
        return;
      }

      const applyDiscount = (nextValue) => {
        dispatch(changeValueInvoiceForm({ invoice: { discount: { value: nextValue } } }));
      }

      if (normalizedValue > 90 && normalizedValue !== previousValue) {
        Modal.confirm({
          title: 'Confirmar descuento alto',
          icon: <ExclamationCircleOutlined />,
          content: 'Un descuento superior al 90% reduce drásticamente la ganancia. ¿Deseas continuar?',
          okText: 'Aplicar descuento',
          cancelText: 'Cancelar',
          onOk: () => {
            applyDiscount(normalizedValue);
          },
          onCancel: () => {
            ignoreDiscountChangeRef.current = true;
            form.setFieldsValue({ discount: { value: previousValue } });
          }
        });
        return;
      }

      applyDiscount(normalizedValue);
      return
    }
    dispatch(changeValueInvoiceForm({ invoice: value }))
  }

  return (
    <Modal
      style={{ top: 10 }}
      title={`Editar factura: #${invoice?.numberID}${isEditLocked ? ' (solo lectura)' : ''}`}
      open={modal.isOpen}
      width={800}
      onCancel={handleCancel}
      destroyOnHidden
      footer={[
        <div key="1" style={{
          float: 'left',
          alignItems: 'center',
          display: 'flex',
          gap: 16,
        }}>
          <div>
            Total: {useFormatPrice(invoice.totalPurchase.value)}
          </div>
          <div>
            Itbis: {useFormatPrice(invoice.totalTaxes.value)}
          </div>
          <div>
            Items: {invoice.totalShoppingItems.value}
          </div>
        </div>,

        <Button key="back" onClick={handleCancel} disabled={loading}>
          Cancelar
        </Button>,
        <Button key="submit" type="primary" onClick={handleOk} loading={loading} disabled={isEditLocked}>
          Guardar
        </Button>,
      ]}
    >
      {isEditLocked ? (
        <Alert
          type="warning"
          showIcon
          style={{ marginBottom: 16 }}
          message="La ventana de edición de 48 horas expiró."
          description="Puedes consultar la información de la factura, pero no es posible modificarla."
        />
      ) : null}
      <Form
        form={form}
        initialValues={invoice}
        layout="vertical"
        onValuesChange={handleChange}
        disabled={isEditLocked}
      >

        <antd.Tabs defaultActiveKey='1' items={sections} />
      </Form>
    </Modal>)
}
  ;

import {Select, Modal, message} from 'antd'
import { useEffect, useMemo, useState } from 'react'
import { useDispatch } from 'react-redux'
import styled from 'styled-components'
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome'
import { faUser, faPhone, faIdCard, faMapMarkerAlt, faChevronDown, faChevronUp } from '@fortawesome/free-solid-svg-icons'

import { changeClientInvoiceForm } from '../../../../../../features/invoice/invoiceFormSlice'
import { useFbGetClients } from '../../../../../../firebase/client/useFbGetClients'

export const Client = ({ invoice, isEditLocked = false }) => {
    const clientData = invoice?.client
    const dispatch = useDispatch()
    const { clients } = useFbGetClients();
    const [isCollapsed, setIsCollapsed] = useState(false);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const readOnly = isEditLocked;

    const genericNames = ['Generic Client', 'Cliente Genérico'];
    const genericIds = ['GC-0000'];
    const isClientObject = clientData && typeof clientData === 'object';
    const isClientEmpty = !isClientObject || Object.keys(clientData).length === 0;
    const normalizedName = typeof clientData?.name === 'string' ? clientData.name.trim() : '';
    const rawClientId = clientData?.id;
    const clientId = typeof rawClientId === 'string'
        ? rawClientId.trim()
        : typeof rawClientId === 'number'
            ? String(rawClientId)
            : '';
    const isGenericClient = isClientEmpty || genericNames.includes(normalizedName) || genericIds.includes(clientId) || !clientId;

    const normalizedClients = Array.isArray(clients) ? clients : [];

    const clientDictionary = useMemo(() => {
        return normalizedClients.reduce((acc, entry) => {
            const client = entry?.client;
            if (client?.id) {
                const key = typeof client.id === 'string' ? client.id : String(client.id);
                acc[key] = client;
            }
            return acc;
        }, {});
    }, [normalizedClients]);

    const options = useMemo(() => {
        return normalizedClients
            .map(({ client }) => ({
                label: client?.name || 'Sin nombre',
                value: client?.id ? (typeof client.id === 'string' ? client.id : String(client.id)) : undefined,
            }))
            .filter(option => Boolean(option.value));
    }, [normalizedClients]);

    const handleChangeClient = (value) => {
        if (readOnly) {
            message.warning('La factura está en modo de solo lectura.');
            return;
        }
        const key = typeof value === 'string' ? value : String(value);
        const selectedClient = clientDictionary[key];

        if (!selectedClient) {
            return;
        }

        dispatch(changeClientInvoiceForm({ client: selectedClient }))
        setIsModalOpen(false)
    }

    const toggleCollapse = () => {
        setIsCollapsed(!isCollapsed)
    }

    useEffect(() => {
        if (readOnly && isModalOpen) {
            setIsModalOpen(false);
        }
    }, [readOnly, isModalOpen]);

    const openModal = () => {
        if (readOnly) {
            message.warning('No puedes cambiar el cliente después de 48 horas.');
            return;
        }
        setIsModalOpen(true)
    }

    const closeModal = () => {
        setIsModalOpen(false)
    }

    const primaryDetails = [
        { icon: faUser, label: 'Nombre', value: clientData?.name },
        { icon: faPhone, label: 'Teléfono', value: clientData?.tel },
        { icon: faIdCard, label: 'ID Personal', value: clientData?.personalID }
    ]

    const secondaryDetails = [
        { icon: faMapMarkerAlt, label: 'Dirección', value: clientData?.address, fullWidth: true }
    ]

    const hasSecondaryDetails = secondaryDetails.some(detail => Boolean(detail.value))

    return (
        <Container>
            {isGenericClient ? (
                <GenericContainer>
                    <GenericTitle>Sin cliente asignado</GenericTitle>
                    <GenericDescription>
                        Agrega un cliente para personalizar la factura y mantener un historial preciso.
                    </GenericDescription>
                    <GenericButton onClick={openModal} disabled={readOnly}>Agregar cliente</GenericButton>
                </GenericContainer>
            ) : (
                <ClientDetailsCard>
                    <CardHeader>
                        <HeaderTitle>Información Cliente</HeaderTitle>
                        <ChangeClientButton onClick={openModal} disabled={readOnly}>
                            <span>Cambiar Cliente</span>
                        </ChangeClientButton>
                    </CardHeader>

                    <PrimaryDetailsGrid>
                        {primaryDetails.map((detail, index) => (
                            detail.value && (
                                <DetailItem key={index}>
                                    <DetailIcon>
                                        <FontAwesomeIcon icon={detail.icon} />
                                    </DetailIcon>
                                    <DetailContent>
                                        <DetailLabel>{detail.label}</DetailLabel>
                                        <DetailValue>{detail.value}</DetailValue>
                                    </DetailContent>
                                </DetailItem>
                            )
                        ))}
                    </PrimaryDetailsGrid>

                    {hasSecondaryDetails && (
                        <>
                            <CollapsibleContent isCollapsed={isCollapsed}>
                                <DetailsGrid>
                                    {secondaryDetails.map((detail, index) => (
                                        detail.value && (
                                            <DetailItem key={index} $fullWidth={detail.fullWidth}>
                                                <DetailIcon>
                                                    <FontAwesomeIcon icon={detail.icon} />
                                                </DetailIcon>
                                                <DetailContent>
                                                    <DetailLabel>{detail.label}</DetailLabel>
                                                    <DetailValue>{detail.value}</DetailValue>
                                                </DetailContent>
                                            </DetailItem>
                                        )
                                    ))}
                                </DetailsGrid>
                            </CollapsibleContent>

                            <FooterActions>
                                <ExpandButton onClick={toggleCollapse}>
                                    <span>{isCollapsed ? 'Ver más' : 'Ver menos'}</span>
                                    <FontAwesomeIcon icon={isCollapsed ? faChevronDown : faChevronUp} />
                                </ExpandButton>
                            </FooterActions>
                        </>
                    )}
                </ClientDetailsCard>
            )}

            <Modal
                title="Seleccionar Cliente"
                open={isModalOpen}
                onCancel={closeModal}
                footer={null}
                width={500}
            >
                <ModalContent>
                    <Select
                        showSearch
                        placeholder="Buscar y seleccionar cliente"
                        filterOption={(input, option) => {
                            const optionLabel = typeof option?.label === 'string' ? option.label : '';
                            return optionLabel.toLowerCase().includes(input.toLowerCase());
                        }}
                        options={options}
                        style={{ width: '100%' }}
                        value={clientDictionary[clientId] ? clientId : undefined}
                        onChange={handleChangeClient}
                        size="large"
                        disabled={readOnly}
                    />
                </ModalContent>
            </Modal>
        </Container>
    )
