import { useState } from 'react';
import { Form, Input, Modal, Spin, Button, message } from 'antd';
import styled from 'styled-components';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faBan, faTriangleExclamation, faWarehouse } from '@fortawesome/free-solid-svg-icons';
import { useDispatch, useSelector } from 'react-redux';

import { selectUser } from '../../../../../../features/auth/userSlice';
import { closeInvoiceForm } from '../../../../../../features/invoice/invoiceFormSlice';
import { fbCancelInvoice } from '../../../../../../firebase/invoices/fbCancelInvoice';
import { Client } from '../Client/Client';
import { InvoiceHeader } from '../InvoiceHeader/InvoiceHeader';
import { PaymentInfoModal } from '../PaymentInfo/PaymentInfoModal';
import { TimeRemainingBadge } from '../TimeRemainingBadge/TimeRemainingBadge';

import { InvoiceResume } from './components/InvoiceResume';

export const InvoiceInfo = ({ invoice, isEditLocked }) => {
  const [isOpenCancelInvoiceConfirm, setIsOpenCancelInvoiceConfirm] = useState(false);
  const [isOpenPaymentInfoModal, setIsOpenPaymentInfoModal] = useState(false);
  const isCancelable = !invoice?.NCF;

  const handleCloseCancelInvoiceConfirm = () => setIsOpenCancelInvoiceConfirm(false);
  const handleOpenCancelInvoiceConfirm = () => setIsOpenCancelInvoiceConfirm(true);
  const handleOpenPaymentInfoModal = () => {
    if (isEditLocked) {
      message.warning('La información de pago es de solo lectura.');
      return;
    }
    setIsOpenPaymentInfoModal(true);
  };
  const handleClosePaymentInfoModal = () => setIsOpenPaymentInfoModal(false);

  return (
    <Container>
      <TimeRemainingBadge invoice={invoice} />
      <InvoiceHeader invoice={invoice} />
      <Client invoice={invoice} isEditLocked={isEditLocked} />
      <InvoiceResume
        invoice={invoice}
        isEditLocked={isEditLocked}
        onOpenPaymentInfo={handleOpenPaymentInfoModal}
      />
      <PaymentInfoModal
        isOpen={isOpenPaymentInfoModal}
        handleClose={handleClosePaymentInfoModal}
        isEditLocked={isEditLocked}
      />
      <ActionsRow>
        <CancelButton
          danger
          disabled={!isCancelable}
          onClick={handleOpenCancelInvoiceConfirm}
        >
          <FontAwesomeIcon icon={faBan} />
          <span>Anular factura</span>
        </CancelButton>
      </ActionsRow>
      <CancelInvoiceConfirm
        isOpen={isOpenCancelInvoiceConfirm}
        invoice={invoice}
        handleClose={handleCloseCancelInvoiceConfirm}
      />
    </Container>
  );
};



const CancelInvoiceConfirm = ({ isOpen, invoice, handleClose }) => {
  const [form] = Form.useForm();
  const [isLoading, setIsLoading] = useState(false);
  const dispatch = useDispatch();
  const user = useSelector(selectUser);

  const handleOk = async () => {
    setIsLoading(true);
    try {
      const values = await form.validateFields();
      const cancellationReason = values.cancellationReason;

      await fbCancelInvoice(user, invoice, cancellationReason);
      dispatch(closeInvoiceForm());
      handleClose();
      antd.message.success('Factura anulada correctamente');
    } catch (error) {
      antd.message.error('Error al anular factura');
    } finally {
      form.resetFields();
      setIsLoading(false);
    }
  };

  const handleCancel = () => {
    form.resetFields();
    handleClose();
  };

  return (
    <Modal
      open={isOpen}
      footer={null}
      onCancel={handleCancel}
      destroyOnClose
      centered
    >
      <Spin spinning={isLoading} tip="Cargando..." size="large">
        <ModalContent>
          <WarningCard>
            <WarningHeader>
              <WarningIcon icon={faTriangleExclamation} />
              <WarningCopy>
                <WarningTitle>Confirmación de anulación</WarningTitle>
                <WarningSubtitle>Esta acción es definitiva</WarningSubtitle>
              </WarningCopy>
            </WarningHeader>

            <WarningList>
              <WarningItem>
                <ListIcon icon={faTriangleExclamation} />
                <span>Esta factura se anulará y no se podrá revertir.</span>
              </WarningItem>
              <WarningItem>
                <ListIcon icon={faWarehouse} />
                <span>Los productos de esta factura volverán al inventario.</span>
              </WarningItem>
            </WarningList>
          </WarningCard>

          <StyledForm
            form={form}
            layout="vertical"
            onFinish={handleOk}
          >
            <StyledFormItem
              label="Motivo de la anulación"
              name="cancellationReason"
              help="Ejemplo: El cliente se arrepintió de la compra"
              rules={[{ required: true, message: 'Por favor ingrese el motivo de la anulación' }]}
            >
              <StyledInput
                type="text"
                placeholder="Motivo de la anulación"
              />
            </StyledFormItem>

            <FormActions>
              <Button onClick={handleCancel}>
                Cancelar
              </Button>
              <Button
                type="primary"
                danger
                onClick={handleOk}
                icon={<FontAwesomeIcon icon={faBan} />}
              >
                Anular
              </Button>
            </FormActions>
          </StyledForm>
        </ModalContent>
      </Spin>
    </Modal>
  );
};

const Container = styled.div`
  display: flex;
  flex-direction: column;
  gap: 1rem;
`;

const ActionsRow = styled.div`
  display: flex;
  justify-content: flex-end;
`;

const CancelButton = styled(Button)`
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  font-weight: 500;
`;

const ModalContent = styled.div`
  display: flex;
  flex-direction: column;
  gap: 1.5rem;
`;

const WarningCard = styled.div`
  display: flex;
  flex-direction: column;
  gap: 1rem;
  padding: 1.25rem;
  border-radius: 12px;
  background: #fff8eb;
  border: 1px solid #fcd34d;
`;

const WarningHeader = styled.div`
  display: flex;
  align-items: center;
  gap: 0.75rem;
`;

const WarningIcon = styled(FontAwesomeIcon)`
  font-size: 1.75rem;
  color: #d97706;
`;

const WarningCopy = styled.div`
  display: flex;
  flex-direction: column;
  gap: 0.1rem;
`;

const WarningTitle = styled.h3`
  margin: 0;
  font-size: 1.1rem;
  color: #1f2937;
`;

const WarningSubtitle = styled.span`
  font-size: 0.9rem;
  color: #6b7280;
`;

const WarningList = styled.ul`
  list-style: none;
  margin: 0;
  padding: 0;
  display: grid;
  gap: 0.75rem;
`;

const WarningItem = styled.li`
  display: flex;
  align-items: flex-start;
  gap: 0.625rem;
  color: #374151;
`;

const ListIcon = styled(FontAwesomeIcon)`
  margin-top: 0.15rem;
  font-size: 1rem;
  color: #d97706;
`;

const StyledForm = styled(Form)`
  display: flex;
  flex-direction: column;
  gap: 1rem;
`;

const StyledFormItem = styled(Form.Item)`
  margin-bottom: 0;
`;

const StyledInput = styled(Input)`
  padding: 0.6rem 0.75rem;
`;

const FormActions = styled.div`
  display: flex;
  justify-content: flex-end;
  gap: 0.75rem;
`;

import * as antd from 'antd'
import React from 'react'
import styled from 'styled-components'
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome'
import {
    faMoneyBillWave,
    faShoppingCart,
    faReceipt,
    faPercentage,
    faShoppingBag,
    faTag,
    faCircleInfo
} from '@fortawesome/free-solid-svg-icons'

import { useFormatPrice } from '../../../../../../../hooks/useFormatPrice'

const { Button, Tooltip } = antd

const PAYMENT_LABEL_TRANSLATIONS = {
    cash: 'Efectivo',
    efectivo: 'Efectivo',
    card: 'Tarjeta',
    tarjeta: 'Tarjeta',
    creditcard: 'Tarjeta',
    debitcard: 'Tarjeta',
    transfer: 'Transferencia',
    transferencia: 'Transferencia',
    transferbank: 'Transferencia',
    banktransfer: 'Transferencia',
    deposit: 'Depósito',
    deposito: 'Depósito',
    cheque: 'Cheque',
    check: 'Cheque'
}

const formatPaymentMethodLabel = rawLabel => {
    if (!rawLabel) return 'Método'
    const normalized = String(rawLabel)
        .toLowerCase()
        .replace(/[\s_-]/g, '')
    return PAYMENT_LABEL_TRANSLATIONS[normalized] ?? rawLabel
}

export const InvoiceResume = ({ invoice, onOpenPaymentInfo, isEditLocked = false }) => {
    const changeAmount = invoice?.change?.value ?? 0
    const totalPurchase = invoice?.totalPurchase?.value ?? 0
    const subtotal = invoice?.totalPurchaseWithoutTaxes?.value ?? 0
    const taxes = invoice?.totalTaxes?.value ?? 0
    const items = invoice?.totalShoppingItems?.value ?? 0
    const discountPercentage = Number(invoice?.discount?.value ?? 0)

    const formattedSubtotal = useFormatPrice(subtotal)
    const formattedTaxes = useFormatPrice(taxes)
    const formattedChange = useFormatPrice(changeAmount)
    const formattedTotal = useFormatPrice(totalPurchase)
    const formattedItems = Number(items).toLocaleString()

    const changeLabel = changeAmount >= 0 ? 'Cambio' : 'Pendiente'

    const changeHelper = changeAmount >= 0
        ? 'Cambio a devolver al cliente'
        : 'Monto pendiente por cobrar'

    const grossTotal = subtotal + taxes
    const discountDifference = grossTotal - totalPurchase
    const normalizedDiscount = discountDifference > 0 ? Math.round(discountDifference * 100) / 100 : 0

    const discountPercentLabel = discountPercentage.toLocaleString('es-DO', {
        maximumFractionDigits: 2,
        minimumFractionDigits: discountPercentage % 1 === 0 ? 0 : 2
    })
    const discountHelperText =
        discountPercentage > 0
            ? `Ahorro del ${discountPercentLabel}% sobre el total`
            : 'Ajuste aplicado al total'
    const formattedDiscount = normalizedDiscount > 0 ? `-${useFormatPrice(normalizedDiscount)}` : null

    const detailItems = [
        {
            icon: faShoppingBag,
            label: 'Artículos vendidos',
            value: formattedItems,
            helper: 'Cantidad total de artículos'
        },
        {
            icon: faReceipt,
            label: 'Subtotal',
            value: formattedSubtotal,
            helper: 'Antes de impuestos'
        },
        {
            icon: faPercentage,
            label: 'Impuestos',
            value: formattedTaxes,
            helper: 'Impuestos facturados'
        }
    ]

    if (normalizedDiscount > 0) {
        detailItems.push({
            icon: faTag,
            label: 'Descuento aplicado',
            value: formattedDiscount,
            helper: discountHelperText,
            status: 'discount'
        })
    }

    detailItems.push(
        {
            icon: faShoppingCart,
            label: 'Total a cobrar',
            value: formattedTotal,
            helper: 'Monto final con descuentos',
            status: 'primary'
        },

    )

    const paymentMethods = Array.isArray(invoice?.paymentMethod) ? invoice.paymentMethod : []
    const activePaymentMethods = paymentMethods.filter(method => method?.status)

    const paymentBreakdown = activePaymentMethods.map(method => {
        const amount = Number(method?.value) || 0
        const rawLabel = method?.name || method?.method || 'Método'
        const label = formatPaymentMethodLabel(rawLabel)
        const helper = method?.reference ? `Ref: ${method.reference}` : null

        return {
            label,
            helper,
            value: useFormatPrice(amount)
        }
    })

    const balanceSummary = {
        label: changeLabel,
        helper: changeHelper,
        value: useFormatPrice(Math.abs(changeAmount)),
        status: changeAmount >= 0 ? 'returned' : 'pending'
    }

    return (
        <Container>
            <ResumeCard>
                <CardHeader>
                    <HeaderText>
                        <HeaderTitle>Resumen de totales</HeaderTitle>
                    </HeaderText>
                    {onOpenPaymentInfo && (
                        <HeaderActions>
                            <Button
                                type="primary"
                                size="small"
                                onClick={onOpenPaymentInfo}
                                disabled={isEditLocked}
                            >
                                Editar pago
                            </Button>
                        </HeaderActions>
                    )}
                </CardHeader>

                <CardBody>
                    <Section>
                        <SectionHeading>Detalle del cálculo</SectionHeading>
                        <RowList>
                            {detailItems.map(item => (
                                <Row key={item.label}>
                                    <RowMain>
                                        {/* <RowIcon data-status={item.status}>
                                            <FontAwesomeIcon icon={item.icon} />
                                        </RowIcon> */}
                                        <RowText>
                                            <RowLabel $status={item.status} $context="detail">
                                                {item.label}
                                            </RowLabel>
                                            <RowHelper $context="detail">
                                                <Tooltip title={item.helper} placement="top" trigger={['hover', 'click']}>
                                                    <InfoIconButton
                                                        type="button"
                                                        aria-label={`Ver más información sobre ${item.label}`}
                                                    >
                                                        <FontAwesomeIcon icon={faCircleInfo} />
                                                    </InfoIconButton>
                                                </Tooltip>
                                            </RowHelper>
                                        </RowText>
                                    </RowMain>
                                    <RowValue $status={item.status} $context="detail">
                                        {item.value}
                                    </RowValue>
                                </Row>
                            ))}
                        </RowList>
                    </Section>

                    <PaymentSection>
                        <SectionHeading>Métodos de pago</SectionHeading>
                        <RowList>
                            {paymentBreakdown.length > 0 ? (
                                paymentBreakdown.map(item => (
                                    <Row key={item.label}>
                                        <RowMain>
                                            <RowText>
                                                <RowLabel $context="detail">{item.label}</RowLabel>
                                                {item.helper && (
                                                    <RowHelper>
                                                        <Tooltip
                                                            title={item.helper}
                                                            placement="top"
                                                            trigger={['hover', 'click']}
                                                        >
                                                            <InfoIconButton
                                                                type="button"
                                                                aria-label={`Ver información adicional de ${item.label}`}
                                                            >
                                                                <FontAwesomeIcon icon={faCircleInfo} />
                                                            </InfoIconButton>
                                                        </Tooltip>
                                                    </RowHelper>
                                                )}
                                            </RowText>
                                        </RowMain>
                                        <RowValue $context="detail">{item.value}</RowValue>
                                    </Row>
                                ))
                            ) : (
                                <EmptyRow>Sin métodos de pago registrados</EmptyRow>
                            )}
                        </RowList>

                        <BalanceRow>
                            <RowMain>
                                <RowText>
                                    <RowLabel
                                        $context="detail"
                                        $status={balanceSummary.status}
                                    >
                                        {balanceSummary.label}
                                    </RowLabel>
                                    <RowHelper>
                                        <Tooltip
                                            title={balanceSummary.helper}
                                            placement="top"
                                            trigger={['hover', 'click']}
                                        >
                                            <InfoIconButton
                                                type="button"
                                                aria-label="Ver información adicional del balance"
                                            >
                                                <FontAwesomeIcon icon={faCircleInfo} />
                                            </InfoIconButton>
                                        </Tooltip>
                                    </RowHelper>
                                </RowText>
                            </RowMain>
                            <RowValue
                                $context="detail"
                                $status={balanceSummary.status}
                            >
                                {balanceSummary.value}
                            </RowValue>
                        </BalanceRow>
                    </PaymentSection>
                </CardBody>
            </ResumeCard>
        </Container>
    )
}

const Container = styled.div`
    width: 100%;
`

const ResumeCard = styled.div`
    border: 1px solid #e8e8e8;
    border-radius: 12px;
    overflow: hidden;
    box-shadow: 0 4px 16px rgba(15, 23, 42, 0.06);
    background: #ffffff;
`

const CardHeader = styled.div`
  display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    background: #fafafa;
    border-bottom: 1px solid #e8e8e8;
`

const HeaderText = styled.div`
    display: flex;
    flex-direction: column;
    gap: 4px;
`

const HeaderLabel = styled.span`
    font-size: 11px;
    font-weight: 600;
    color: #7d8597;
    letter-spacing: 0.6px;
    text-transform: uppercase;
`

const HeaderTitle = styled.div`
    font-size: 14px;
    font-weight: 600;
    color: #262626;
`

const HeaderActions = styled.div`
    display: flex;
    align-items: center;
`

