import { Button } from 'antd'
import { type FC } from 'react'
import styled from 'styled-components'

import { DiscountSection } from './components/DiscountSection'
import { PaymentMethodsSection } from './components/PaymentMethodsSection'
import { PaymentSummary } from './components/PaymentSummary'
import { usePaymentInfo } from './hooks/usePaymentInfo'
import type { PaymentInfoProps } from './types'

export const PaymentInfo: FC<PaymentInfoProps> = ({
    isEditLocked = false,
    onContinue = null
}) => {
    const {
        paymentMethods,
        readOnly,
        formattedTotalPurchase,
        formattedTotalPayment,
        balance,
        discountType,
        discountValue,
        subtotal,
        handleStatusChange,
        handleValueChange,
        handleReferenceChange,
        handleDiscountTypeChange,
        handleDiscountValueChange
    } = usePaymentInfo({ isEditLocked })

    return (
        <Container>
            <DiscountSection
                discountType={discountType}
                discountValue={discountValue}
                subtotal={subtotal}
                readOnly={readOnly}
                onDiscountTypeChange={handleDiscountTypeChange}
                onDiscountValueChange={handleDiscountValueChange}
            />
            <PaymentCard>
                <CardContent>
                    <PaymentMethodsSection
                        paymentMethods={paymentMethods}
                        readOnly={readOnly}
                        onStatusChange={handleStatusChange}
                        onValueChange={handleValueChange}
                        onReferenceChange={handleReferenceChange}
                    />

                    <PaymentSummary
                        formattedTotalPurchase={formattedTotalPurchase}
                        formattedTotalPayment={formattedTotalPayment}
                        balance={balance}
                    />

                </CardContent>
            </PaymentCard>

            {onContinue && (
                <ContinueButtonContainer>
                    <ContinueButton
                        type='primary'
                        size='large'
                        onClick={onContinue}
                        block
                    >
                        Continuar
                    </ContinueButton>
                </ContinueButtonContainer>
            )}
        </Container>
    )
}

