import { Modal, Button, Tooltip } from 'antd';
import { useEffect, useMemo, useState } from 'react';
import styled from 'styled-components';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import {
  faBoxOpen,
  faBoxesStacked,
  faCircleInfo,
  faTimes,
  faPlus,
} from '@fortawesome/free-solid-svg-icons';
import { useFormatPrice } from '../../../../../../hooks/useFormatPrice';
import { getTotalPrice } from '../../../../../../utils/pricing';
import { StyledProductTable } from './ProductTables.styles';
import { ProductFilterToolbar } from './ProductFilterToolbar';
import {
  getCategoryName,
  getPrimaryActiveIngredient,
  getCategoryStats,
} from './productDataUtils';

export const ProductListModal = ({ isVisible, onClose, products, onAddProduct, isReadOnly = false }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [sortField, setSortField] = useState('name');
  const [sortDirection, setSortDirection] = useState('asc');
  const [categoryFilter, setCategoryFilter] = useState('all');

  useEffect(() => {
    if (isReadOnly && isVisible) {
      onClose();
    }
  }, [isReadOnly, isVisible, onClose]);

  const sortOptions = useMemo(
    () => [
      { label: 'Producto', value: 'name' },
      { label: 'Precio', value: 'price' },
      { label: 'Stock', value: 'stock' },
    ],
    [],
  );

  const categoryStats = useMemo(() => getCategoryStats(products), [products]);

  useEffect(() => {
    if (categoryFilter === 'all') return;
    const hasSelectedCategory = categoryStats.entries.some((entry) => entry.name === categoryFilter);
    if (!hasSelectedCategory) {
      setCategoryFilter('all');
    }
  }, [categoryFilter, categoryStats]);

  const displayProducts = useMemo(() => {
    const list = Array.isArray(products) ? products : [];
    const normalizedSearch = searchTerm.trim().toLowerCase();

    const filteredBySearch = normalizedSearch
      ? list.filter((product) => {
          const name = product?.name?.toLowerCase() ?? '';
          return name.includes(normalizedSearch);
        })
      : [...list];

    const filtered = categoryFilter === 'all'
      ? filteredBySearch
      : filteredBySearch.filter((product) => getCategoryName(product?.category) === categoryFilter);

    const directionMultiplier = sortDirection === 'desc' ? -1 : 1;

    const sorted = [...filtered].sort((a, b) => {
      switch (sortField) {
        case 'price':
          return (getTotalPrice(a) - getTotalPrice(b)) * directionMultiplier;
        case 'stock':
          return (((a?.stock ?? 0) - (b?.stock ?? 0)) * directionMultiplier);
        case 'name':
        default:
          return ((a?.name ?? '').localeCompare(b?.name ?? '')) * directionMultiplier;
      }
    });

    return sorted;
  }, [products, searchTerm, categoryFilter, sortField, sortDirection]);

  const columns = [
    {
      title: 'Producto',
      dataIndex: ['name'],
      key: 'name',
      width: 360,
      ellipsis: true,
      sorter: (a, b) => (a?.name ?? '').localeCompare(b?.name ?? ''),
      render: (text, record) => {
        const category = getCategoryName(record?.category);
        const activeIngredient = getPrimaryActiveIngredient(record?.activeIngredients);
        const hasMeta = Boolean(category || activeIngredient);

        return (
          <ProductName>
            <ProductPrimaryText title={record.name}>{record.name}</ProductPrimaryText>
            {hasMeta && (
              <ProductMeta>
                {category ? <CategoryPill title={category}>{category}</CategoryPill> : null}
                {activeIngredient ? (
                  <ActiveIngredientPill title={activeIngredient}>{activeIngredient}</ActiveIngredientPill>
                ) : null}
              </ProductMeta>
            )}
          </ProductName>
        );
      },
    },
    {
      title: 'Stock',
      dataIndex: ['stock'],
      key: 'stock',
      width: 120,
      sorter: (a, b) => (a?.stock ?? 0) - (b?.stock ?? 0),
      render: (_, record) => {
        const stockValue = Number(record?.stock ?? 0);
        return <StockBadge $isLow={stockValue <= 0}>{stockValue}</StockBadge>;
      },
    },
    {
      title: 'Precio Unitario',
      dataIndex: ['pricing', 'price'],
      key: 'price',
      width: 160,
      align: 'right',
      sorter: (a, b) => getTotalPrice(a) - getTotalPrice(b),
      render: (text, record) => useFormatPrice(getTotalPrice(record)),
    },
    {
      title: '',
      key: 'actions',
      width: 100,
      render: (_, record) => (
        <Tooltip title={isReadOnly ? 'Edición deshabilitada' : 'Agregar'}>
          <ActionButton
            type="button"
            onClick={() => {
              if (isReadOnly) return;
              onAddProduct(record)
            }}
            aria-label={`Agregar ${record.name}`}
            disabled={isReadOnly}
          >
            <ActionIcon icon={faPlus} />
          </ActionButton>
        </Tooltip>
      ),
    },
  ];

  const paginationConfig = {
    pageSize: 15,
    position: ['bottomCenter'],
    showSizeChanger: false,
  };

  return (
    <StyledModal
      title={null}
      open={isVisible && !isReadOnly}
      onCancel={onClose}
      footer={null}
      width={860}
    >
      <ModalContent>
        <Header>
          <TitleGroup>
            <HeaderIcon icon={faBoxOpen} />
            <HeaderText>
              <Title>Agregar Producto a la Factura</Title>
            </HeaderText>
          </TitleGroup>
        </Header>

        <ProductFilterToolbar
          searchTerm={searchTerm}
          onSearchChange={setSearchTerm}
          searchPlaceholder="Buscar producto"
          categoryFilter={categoryFilter}
          onCategoryChange={setCategoryFilter}
          categoryStats={categoryStats}
          sortField={sortField}
          sortOptions={sortOptions}
          onSortFieldChange={setSortField}
          sortDirection={sortDirection}
          onToggleSortDirection={() => setSortDirection((prev) => (prev === 'asc' ? 'desc' : 'asc'))}
        />

        <StyledProductTable
          dataSource={displayProducts}
          columns={columns}
          pagination={paginationConfig}
          rowKey="id"
          scroll={{ y: 400 }}
        />

        <SummaryRow>
          <SummaryChip>
            <SummaryIcon icon={faBoxesStacked} />
            {displayProducts.length} productos
          </SummaryChip>
        </SummaryRow>

        <ModalFooter>
          <FooterNote>
            <NoteIcon icon={faCircleInfo} />
            Los precios reflejan los impuestos configurados en tu catálogo.
          </FooterNote>
          <CloseButton onClick={onClose}>
            <CloseIcon icon={faTimes} />
            Cerrar
          </CloseButton>
        </ModalFooter>
      </ModalContent>
    </StyledModal>
  );
};

const StyledModal = styled(Modal)`
  top: 10px;

  .ant-modal-content {
    border-radius: 18px;
    overflow: hidden;
    box-shadow: 0 26px 60px rgba(15, 23, 42, 0.18);
    padding: 0;
  }

  .ant-modal-body {
    padding: 28px;
    background: #f9fafb;
  }
`;

const ModalContent = styled.div`
  display: flex;
  flex-direction: column;
  gap: 1em;
`;

const Header = styled.header`
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-wrap: wrap;
  gap: 18px;
`;

const TitleGroup = styled.div`
  display: flex;
  align-items: center;
  gap: 16px;
`;

const HeaderIcon = styled(FontAwesomeIcon)`
  font-size: 32px;
  color: #1d4ed8;
  background: rgba(29, 78, 216, 0.12);
  border-radius: 16px;
  padding: 12px;
`;

const HeaderText = styled.div`
  display: flex;
  flex-direction: column;
  gap: 4px;
`;

const Title = styled.h2`
  margin: 0;
  font-size: 20px;
  font-weight: 700;
  color: #111827;
`;

const SummaryChip = styled.div`
  display: inline-flex;
  align-items: center;
  gap: 10px;
  padding: 10px 18px;
  border-radius: 999px;
  background: #e0f2fe;
  color: #0c4a6e;
  font-weight: 600;
`;

const SummaryIcon = styled(FontAwesomeIcon)`
  font-size: 18px;
`;

const SummaryRow = styled.div`
  display: flex;
  justify-content: flex-end;
`;

const Toolbar = styled.div`
  display: flex;
  flex-wrap: wrap;
  gap: 16px;
  align-items: flex-start;
  padding: 8px 12px;
  background: #ffffff;
  border-radius: 14px;
  box-shadow: 0 14px 32px rgba(15, 23, 42, 0.05);
`;

const ProductName = styled.div`
  display: flex;
  flex-direction: column;
  align-items: flex-start;
  gap: 8px;
  font-weight: 600;
  color: #1f2937;
  max-width: 100%;
`;

const ProductPrimaryText = styled.span`
  max-width: 100%;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
`;

const ProductMeta = styled.div`
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
`;

const MetaPill = styled.span`
  display: inline-flex;
  align-items: center;
  padding: 4px 10px;
  border-radius: 999px;
  font-size: 12px;
  font-weight: 500;
  max-width: 200px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
`;

const CategoryPill = styled(MetaPill)`
  background: #eef2ff;
  color: #3730a3;
`;

const ActiveIngredientPill = styled(MetaPill)`
  background: #ecfdf5;
  color: #047857;
`;

const StockBadge = styled.div`
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 64px;
  padding: 6px 12px;
  border-radius: 999px;
  font-weight: 600;
  font-size: 13px;
  background: ${({ $isLow }) => ($isLow ? '#fee2e2' : '#ecfdf5')};
  color: ${({ $isLow }) => ($isLow ? '#991b1b' : '#047857')};
`;

const ActionButton = styled.button`
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 42px;
  height: 42px;
  border-radius: 999px;
  background: #f3f4f6;
  border: none;
  cursor: ${props => (props.disabled ? 'not-allowed' : 'pointer')};
  opacity: ${props => (props.disabled ? 0.5 : 1)};
  transition: background 0.2s ease, transform 0.2s ease;
  padding: 0;

  &:hover {
    ${props => props.disabled ? '' : `
    background: #e5e7eb;
    transform: translateY(-1px);
    `}
  }

  &:focus-visible {
    outline: 2px solid #2563eb;
    outline-offset: 2px;
  }

  &:active {
    ${props => props.disabled ? '' : 'transform: translateY(0);'}
  }
`;

const ActionIcon = styled(FontAwesomeIcon)`
  font-size: 16px;
  color: #1f2937;
`;

const ModalFooter = styled.footer`
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
  flex-wrap: wrap;
`;

const FooterNote = styled.div`
  display: inline-flex;
  align-items: center;
  gap: 10px;
  font-size: 13px;
  color: #6b7280;
`;

const NoteIcon = styled(FontAwesomeIcon)`
  font-size: 16px;
  color: #2563eb;
`;

const CloseButton = styled(Button)`
  && {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    font-weight: 600;
  }
`;

const CloseIcon = styled(FontAwesomeIcon)`
  font-size: 14px;
`;

import styled from 'styled-components';
import { Table as AntTable } from 'antd';

export const StyledProductTable = styled(AntTable)`
  background: #ffffff;
  border-radius: 16px;
  border: 1px solid #e5e7eb;
  overflow: hidden;

  .ant-table {
    background: transparent;
  }

  .ant-table-thead > tr > th {
    background: #ffffffff !important;
    color: #374151;
    font-weight: 600;
    font-size: 13px;
    border-bottom: 1px solid #dadbdbff;
  }

  .ant-table-tbody > tr > td {
    border-bottom: 1px solid #f3f4f6;
    font-size: 14px;
    color: #1f2937;
    border: 1px solid transparent;
  }

  .ant-table-tbody > tr:hover > td {
    background: rgba(204, 204, 204, 0.2) !important;
    // border: 1px solid #dbeafe !important;
  }
  .ant-table-tbody > tr:hover {
    background: #ffffffff !important;
    border: 1px solid #dbeafe !important;
  }
`;

import * as antd from 'antd'
import React, { useEffect, useMemo, useState } from 'react'
import { useDispatch } from 'react-redux'
import styled from 'styled-components'

import { icons } from '../../../../../../constants/icons/icons'
import { addProductInvoiceForm, changeAmountToBuyProduct, deleteProductInvoiceForm } from '../../../../../../features/invoice/invoiceFormSlice'
import { useFormatPrice } from '../../../../../../hooks/useFormatPrice'

const { Button, Input } = antd
import { useGetProducts } from '../../../../../../firebase/products/fbGetProducts'
import { getTotalPrice } from '../../../../../../utils/pricing'

import { ProductListModal } from './ProductListModal'
import { StyledProductTable } from './ProductTables.styles'
import { ProductFilterToolbar } from './ProductFilterToolbar'
import { getCategoryName, getCategoryStats } from './productDataUtils'

const getProductQuantity = (product) => {
    if (!product) return 1
    const { amountToBuy } = product

    if (typeof amountToBuy === 'number') {
        return amountToBuy > 0 ? amountToBuy : 1
    }

    if (amountToBuy && typeof amountToBuy === 'object') {
        const total = Number(amountToBuy.total)
        const unit = Number(amountToBuy.unit)

        if (!Number.isNaN(total) && total > 0) return total
        if (!Number.isNaN(unit) && unit > 0) return unit
    }

    return 1
}

const getFormattedUnitPrice = (product) => {
    const quantity = getProductQuantity(product)
    const total = getTotalPrice(product)
    const unitPrice = quantity > 0 ? total / quantity : total
    return useFormatPrice(unitPrice)
}

const getFormattedTotalPrice = (product) => useFormatPrice(getTotalPrice(product))

export const Products = ({ invoice, isEditLocked = false }) => {
    const dispatch = useDispatch()
    const [isProductListModalVisible, setProductListModalVisible] = useState(false)
    const { products } = useGetProducts()
    const [searchTerm, setSearchTerm] = useState('')
    const [sortField, setSortField] = useState('name')
    const [sortDirection, setSortDirection] = useState('asc')
    const [categoryFilter, setCategoryFilter] = useState('all')

    const sortOptions = useMemo(
        () => [
            { label: 'Producto', value: 'name' },
            { label: 'Precio', value: 'price' },
            { label: 'Stock', value: 'stock' },
        ],
        [],
    )

    const invoiceProducts = Array.isArray(invoice?.products) ? invoice.products : []
    const readOnly = isEditLocked
    const categoryStats = useMemo(() => getCategoryStats(invoiceProducts), [invoiceProducts])

    useEffect(() => {
        if (categoryFilter === 'all') return
        const hasSelectedCategory = categoryStats.entries.some((entry) => entry.name === categoryFilter)
        if (!hasSelectedCategory) {
            setCategoryFilter('all')
        }
    }, [categoryFilter, categoryStats])

    const displayProducts = useMemo(() => {
        const normalizedSearch = searchTerm.trim().toLowerCase()

        const filteredBySearch = normalizedSearch
            ? invoiceProducts.filter((product) => {
                const name = product?.name?.toLowerCase() ?? ''
                return name.includes(normalizedSearch)
            })
            : [...invoiceProducts]

        const filtered = categoryFilter === 'all'
            ? filteredBySearch
            : filteredBySearch.filter((product) => getCategoryName(product?.category) === categoryFilter)

        const directionMultiplier = sortDirection === 'desc' ? -1 : 1

        const sorted = [...filtered].sort((a, b) => {
            switch (sortField) {
                case 'price':
                    return (getTotalPrice(a) - getTotalPrice(b)) * directionMultiplier
                case 'stock':
                    return ((a?.stock ?? 0) - (b?.stock ?? 0)) * directionMultiplier
                case 'name':
                default:
                    return ((a?.name ?? '')?.localeCompare(b?.name ?? '')) * directionMultiplier
            }
        })

        return sorted
    }, [invoiceProducts, searchTerm, categoryFilter, sortField, sortDirection])

    const columns = [
        {
            title: 'Producto',
            dataIndex: 'name',
            key: 'productName',
        },
        {
            title: 'Cantidad',
            dataIndex: 'amountToBuy',
            key: 'amountToBuy',
            render: (text, record, index) => (
                <Counter>
                    <Button
                        onClick={() => {
                            if (readOnly) {
                                antd.message.warning('No puedes modificar productos después de 48 horas.');
                                return;
                            }
                            dispatch(changeAmountToBuyProduct({ product: record, type: "subtract" }))
                        }}
                        icon={icons.mathOperations.subtract}
                        disabled={readOnly}
                    />
                    <Input
                        value={record.amountToBuy}
                        onChange={(e) => {
                            if (readOnly) {
                                antd.message.warning('No puedes modificar productos después de 48 horas.');
                                return;
                            }
                            const value = e.target.value;
                            const isValidNumber = !isNaN(parseFloat(value)) && isFinite(value);
                            if (isValidNumber) {
                                dispatch(changeAmountToBuyProduct({ product: record, amount: Number(value), type: "change" }))
                            }
                        }}
                        disabled={readOnly}
                    />
                    <Button
                        onClick={() => {
                            if (readOnly) {
                                antd.message.warning('No puedes modificar productos después de 48 horas.');
                                return;
                            }
                            dispatch(changeAmountToBuyProduct({ product: record, type: "add" }))
                        }}
                        icon={icons.operationModes.add}
                        disabled={readOnly}
                    />
                </Counter>
            ),
        },
        {
            title: 'Precio Unitario',
            dataIndex: 'price',
            key: 'unitPrice',
            align: 'left',
            render: (_, record) => getFormattedUnitPrice(record),
        },
        {
            title: 'Precio Total',
            key: 'totalPrice',
            align: 'left',
            render: (_, record) => getFormattedTotalPrice(record),
        },
        {
            title: 'Acciones',
            key: 'actions',
            align: 'left',

            render: (text, record) => (
                <Button
                    onClick={() => {
                        if (readOnly) {
                            antd.message.warning('No puedes modificar productos después de 48 horas.');
                            return;
                        }
                        dispatch(deleteProductInvoiceForm({ product: record, }))
                    }}
                    icon={icons.operationModes.delete}
                    disabled={readOnly}
                />
            ),
        }
    ];
    const [paginationState, setPaginationState] = useState({
        current: 1,
        pageSize: 5,
    })

    const paginationConfig = {
        pageSize: paginationState.pageSize,
        current: paginationState.current,
        position: ["bottomCenter"],
        showSizeChanger: false,
        onChange: (page, pageSize) => {
            setPaginationState({ current: page, pageSize })
        },
