// React component
const ImageManager = ({ hideImageManager }) => {
  const user = useSelector(selectUser);
  const [images, setImages] = useState([]);
  const [fileList, setFileList] = useState([]);
  const { product } = useSelector(selectUpdateProductData);
  const productImg = product?.image;
  const dispatch = useDispatch();

  const updateFileListWithProgress = (file, progress) => {
    setFileList(prevFileList => prevFileList.map(f => {
      if (f.uid === file.uid) {
        return { ...f, percent: progress, name: file.name, status: 'uploading' };
      }
      return f;
    }));
  };

  const uploadProps = {
    name: 'file',
    multiple: false,
    fileList,
    showUploadList: false,
    customRequest: async ({ file, onProgress }) => {
      try {
        const newFile = { ...file, percent: 0, status: 'uploading' };
        setFileList([newFile]);

        const updateProgress = (progress) => {
          updateFileListWithProgress(file, progress);
          if (onProgress) {
            onProgress({ percent: progress });
          }
        };

        const url = await fbAddProductImg(user, file, updateProgress);
        await fbAddProductImgData(user, url);
        message.success('Imagen cargada correctamente');
        setFileList([{ ...newFile, status: 'done', url }]);
      } catch (error) {
        message.error('Error al cargar la imagen');
        setFileList([{ ...file, status: 'error' }]);
      } finally {
        setTimeout(() => setFileList([]), 1000);
      }
    },
    beforeUpload: (file) => {
      const isImage = file.type.startsWith('image/');
      if (!isImage) {
        message.error('Solo se permiten archivos de imagen');
        return false;
      }
      const isLt5M = file.size / 1024 / 1024 < 5;
      if (!isLt5M) {
        message.error('El archivo debe ser menor a 5MB');
        return false;
      }
      return true;
    },
  };

  useEffect(() => {
    fbGetProductsImg(user, setImages);
  }, [user]);

  const uploadProgress = fileList.length > 0 ? fileList[0].percent : 0;
  const isUploading = fileList.length > 0 && fileList[0].status === 'uploading';

  const handleRemoveImage = () => {
    dispatch(ChangeProductImage(null));
  };

  return (
    <Container>
      <Header>
        <Button
          icon={<ArrowLeftOutlined />}
          onClick={hideImageManager}
          type="default"
        >
          Volver
        </Button>

      </Header>

      <MainContent>
        <UploadSection>
          <SectionTitle>
            <InboxOutlined />
            Cargar Imagen
          </SectionTitle>

          <UploadContainer>
            <Upload.Dragger {...uploadProps}>
              <p className="ant-upload-drag-icon">
                <InboxOutlined />
              </p>
              <p className="ant-upload-text">
                Seleccionar imagen del producto
              </p>
              <p className="ant-upload-hint">
                JPG, PNG o GIF • Máximo 5MB
              </p>
            </Upload.Dragger>

            {isUploading && (
              <ProgressContainer>
                <Typography.Text strong style={{ marginBottom: 16, color: '#374151', textAlign: 'center' }}>
                  Cargando imagen...
                </Typography.Text>
                <Progress 
                  percent={Math.round(uploadProgress)} 
                  status="active"
                  strokeColor={{
                    '0%': '#3b82f6',
                    '100%': '#1d4ed8',
                  }}
                  style={{ width: '80%' }}
                />
              </ProgressContainer>
            )}
          </UploadContainer>
        </UploadSection>

        <PreviewSection>
          <SectionTitle>
            <PictureOutlined />
            Vista Previa
          </SectionTitle>

          <PreviewCard>
            <ImagePreview>
              {productImg ? (
                <ant.Image
                  src={productImg}
                  alt="Imagen del producto"
                  width="100%"
                  height="100%"
                  style={{ objectFit: 'cover' }}
                  fallback={imgFailed}
                />
              ) : (
                <PictureOutlined className="no-image" />
              )}
            </ImagePreview>

            <ButtonGroup>
              <Button
                disabled={!productImg}
                onClick={handleRemoveImage}
                icon={<DeleteOutlined />}
                danger
                block
                size="small"
              >
                Remover
              </Button>
            </ButtonGroup>
          </PreviewCard>
        </PreviewSection>
      </MainContent>

      <GallerySection>
        <SectionTitle>
          <PictureOutlined />
          Imágenes Disponibles
        </SectionTitle>

        <GalleryContainer>
          <HelpText>
            💡 Selecciona una imagen de la galería para asignarla al producto
          </HelpText>
          <Gallery images={images} />
        </GalleryContainer>
      </GallerySection>
    </Container>
  );
};

