  position: absolute;
  top: 100%;
  ${(p) => (p.$placement === 'right' ? 'right: 0;' : p.$placement === 'center' ? 'left: 50%; transform: translateX(-50%);' : 'left: 0;')}
  margin-top: 4px;
  background: #ffffff;
  border: 1px solid #ffd666;
  box-shadow: 0 4px 12px rgba(0,0,0,.12);
  border-radius: 6px;
  z-index: ${(p) => p.$zIndex || 20};
  padding: 16px;
  min-width: 280px;
  max-width: ${(p) => p.$maxWidth || 340}px;
  font-size: 13px;
`;

const Title = styled.div`
  font-weight: 600;
  font-size: 13px;
  margin-bottom: 12px;
  color: #262626;
  text-align: center;
`;

const SuggestionText = styled.div`
  font-size: 14px;
  font-weight: 500;
  color: #595959;
  text-align: center;
  margin-bottom: 16px;
`;

const Row = styled.div`
  display: flex;
  justify-content: center;
  align-items: center;
  gap: 4px;
  margin-bottom: 16px;
  font-family: 'JetBrains Mono','Fira Code', monospace;
  font-size: 18px;
