export const expandNodePath = (nodeId, nodes) => {
    const findAndExpandPath = (currentNodes, targetId, path = []) => {
        for (let node of currentNodes) {
            const currentPath = [...path, node.id];
            if (node.id === targetId) {
                setExpandedNodes(prev => ({
                    ...prev,
                    ...currentPath.reduce((acc, id) => ({ ...acc, [id]: true }), {})
                }));
                return true;
            }
            if (node.children && findAndExpandPath(node.children, targetId, currentPath)) {
                return true;
            }
        }
        return false;
    };

    findAndExpandPath(nodes, nodeId);
};

export const expandAll = (nodes, setExpandedNodes) => {
    const expandedState = {};
    const traverse = (currentNodes) => {
        currentNodes.forEach(node => {
            if (node.children) {
                expandedState[node.id] = true;
                traverse(node.children);
            }
        });
    };
    traverse(nodes);
    setExpandedNodes(expandedState);
};

export const collapseAll = (setExpandedNodes) => {
    setExpandedNodes({});
};

import { useState, useEffect } from "react";

import { expandMatchingNodes } from "../utils/expandUtils";
import { traverse } from "../utils/traverseUtils";

const useSearchTerm = (data, manuallyClosedNodes, setSearchExpandedNodes) => {
  const [searchTerm, setSearchTerm] = useState("");

  useEffect(() => {
    if (!searchTerm) {
      setSearchExpandedNodes({});
      return;
    }

    const timeoutId = setTimeout(() => {
      expandMatchingNodes(searchTerm, data, traverse, (expandedResult) => {
        const filtered = Object.keys(expandedResult).reduce((acc, nodeId) => {
          if (!manuallyClosedNodes[nodeId]) {
            acc[nodeId] = true;
          }
          return acc;
        }, {});

        setSearchExpandedNodes((prev) => {
          // Mantener solo los nodos que coinciden con la búsqueda actual
          const newExpanded = { ...filtered };
          return newExpanded;
        });
      });
    }, 300); // Debounce para evitar múltiples actualizaciones

    return () => clearTimeout(timeoutId);
  }, [searchTerm, data, manuallyClosedNodes, setSearchExpandedNodes]);

  return { searchTerm, setSearchTerm };
};

export default useSearchTerm;
